const closeBtn = document.querySelector('.close-btn');

// We know the button is INSIDE the modal. 
// We traverse UP to find the parent modal and hide it.
closeBtn.addEventListener('click', function() {
  // Using .closest() is the safest way to traverse upwards!
  const modalWrapper = this.closest('.modal');
  modalWrapper.style.display = 'none';
});

// Other common traversal methods:
const list = document.querySelector('ul');
console.log(list.firstElementChild); // the first <li>
console.log(list.children); // HTMLCollection of all <li>s
console.log(list.nextElementSibling); // The element directly after the <ul>
